@page "/book-appointment"
@rendermode InteractiveServer
@using sv_615b5fd9d8f543d5aa31b2229502a60c.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3>Book an Appointment</h3>

@* ── STEP 1 ── *@
<EditForm EditContext="step1Context" OnValidSubmit="HandleStep1Valid" FormName="step1">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="model.PatientName" />
        <ValidationMessage For="() => model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
        <ValidationMessage For="() => model.Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="model.Phone" />
        <ValidationMessage For="() => model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => model.InsuranceProvider" />
    </div>

    <button type="submit" class="btn btn-primary">Next</button>
</EditForm>

@* ── STEP 2 ── *@
@if (showStep2)
{
    <hr />
    <h4>Appointment Details</h4>

    <EditForm EditContext="step2Context" OnSubmit="HandleStep2Submit" FormName="step2">
        <DataAnnotationsValidator />
        <CustomValidator @ref="customValidator" />

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="model.Doctor">
                <option value="">-- Select --</option>
                @foreach (var doc in doctors)
                {
                    <option value="@doc">@doc</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.Doctor" />
        </div>

        <div class="mb-3">
            <label class="form-label">Appointment Date</label>
            <InputDate class="form-control" @bind-Value="model.AppointmentDate" @bind:after="OnDateChanged" />
            <ValidationMessage For="() => model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="model.ReasonForVisit" rows="3" />
            <ValidationMessage For="() => model.ReasonForVisit" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@isSubmitting">
            @(isSubmitting ? "Checking..." : "Check Availability")
        </button>
        <button type="button" class="btn btn-outline-secondary ms-2" @onclick="GoBackToStep1">Back</button>
    </EditForm>
}

@if (isConfirmed)
{
    <div class="alert alert-success mt-3">
        Appointment booked successfully for @model.PatientName with @model.Doctor
        on @model.AppointmentDate?.ToString("MMM dd, yyyy") at @model.TimeSlot.
    </div>
}

@code {
    private AppointmentModel model = new();
    private EditContext step1Context = default!;
    private EditContext step2Context = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool isConfirmed;

    private List<string> doctors = [];
    private List<string> timeSlots = [];

    protected override void OnInitialized()
    {
        step1Context = new EditContext(model);
        step2Context = new EditContext(model);
    }

    private async Task HandleStep1Valid()
    {
        doctors = await AppointmentSvc.GetDoctorsAsync();
        showStep2 = true;
        isConfirmed = false;

        // Rebuild step2 context so validation state is fresh
        step2Context = new EditContext(model);
    }

    private async Task OnDateChanged()
    {
        if (model.Doctor is not null && model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                model.Doctor, model.AppointmentDate.Value);
            model.TimeSlot = null;
        }
    }

    private async Task HandleStep2Submit()
    {
        customValidator?.ClearErrors();

        if (!step2Context.Validate())
            return;

        isSubmitting = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                model.Email ?? "",
                model.InsuranceProvider ?? "",
                model.Doctor ?? "",
                model.TimeSlot ?? "");

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            isConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private void GoBackToStep1()
    {
        showStep2 = false;
        isConfirmed = false;
    }
}

